import React from "react";
import { Transition, Button, List, Segment } from "semantic-ui-react";

export default function ExternalLinks() {
  const [visible, setVisible] = React.useState(false);
  function toggleVisibility() {
    setVisible(!visible);
  }
  return (
    <div>
      <Button
        basic
        fluid
        content="External Links"
        onClick={toggleVisibility}
        icon={`angle ${visible ? "up" : "down"}`}
      />
      <Transition
        visible={visible}
        animation="slide down"
        duration={500}
        unmountOnHide
      >
        <List
          as={Segment}
          divided
          relaxed
          style={{ textAlign: "left", paddingBottom: 10 }}
        >
          <List.Item>
            <List.Icon name="linkify" verticalAlign="middle" />
            <List.Content>
              <List.Header as="a" href="https://jpg.store">
                JPG.store
              </List.Header>
            </List.Content>
          </List.Item>
        </List>
      </Transition>
    </div>
  );
}
