import React from "react";
import { Transition, Button, Segment, List } from "semantic-ui-react";

const policyIds = [
  {
    text: "(ϟINK) bb1afa523a767b7ae5c5a6083af24eb68a91fe7e583680c822d28ba1",
    link: "https://pool.pm/asset1w47qhp0gdlufe37xqx3l7e85m6kutj4l80vgaz",
  },
];

export default function Policies() {
  const [visible, setVisible] = React.useState(false);
  function toggleVisibility() {
    setVisible(!visible);
  }
  return (
    <div>
      <Button
        basic
        fluid
        content="Policy IDs"
        onClick={toggleVisibility}
        icon={`angle ${visible ? "up" : "down"}`}
      />
      <Transition
        visible={visible}
        animation="slide down"
        duration={500}
        unmountOnHide
      >
        <Segment>
          <List divided relaxed>
            {policyIds.map((option, idx) => (
              <List.Item key={idx} className="relaxed">
                <a className="pid" href={option.link}>
                  {option.text}
                </a>
              </List.Item>
            ))}
          </List>
        </Segment>
      </Transition>
    </div>
  );
}
