import React from "react";
import { Transition, Button, Accordion, Icon } from "semantic-ui-react";

export default function Faq() {
  const [visible, setVisible] = React.useState(false);
  const [activeIndex, setActiveIndex] = React.useState(-1);
  function toggleVisibility() {
    setVisible(!visible);
  }
  function handleClick(_, titleProps) {
    const { index } = titleProps;
    const newIndex = activeIndex === index ? -1 : index;
    setActiveIndex(newIndex);
  }
  return (
    <div style={{ marginBottom: 30 }}>
      <Button
        basic
        fluid
        content="FAQ"
        onClick={toggleVisibility}
        icon={`angle ${visible ? "up" : "down"}`}
      />
      <Transition
        visible={visible}
        animation="slide down"
        duration={500}
        unmountOnHide
      >
        <Accordion styled fluid>
          {faqs.map((faq, index) => (
            <React.Fragment key={index}>
              <Accordion.Title
                active={activeIndex === index}
                index={index}
                onClick={handleClick}
                style={{ texAlign: "left" }}
              >
                <Icon name="dropdown" />
                <span dangerouslySetInnerHTML={{ __html: faq.q }} />
              </Accordion.Title>
              <Accordion.Content active={activeIndex === index}>
                <p dangerouslySetInnerHTML={{ __html: faq.a }}></p>
              </Accordion.Content>
            </React.Fragment>
          ))}
        </Accordion>
      </Transition>
    </div>
  );
}

