import React, { useState } from "react";
import { Segment, Icon, Modal, Image } from "semantic-ui-react";
import tblMin from "../images/squid_poker_table-min.gif";
import tbl from "../images/squid_poker_table.gif";

export default function Slogan() {
  const [open, setOpen] = useState(false);
  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);
  return (
    <div className="header">
      <Segment className="top-segment">
        <div className="social">
          <a href="https://discord.gg/7XkCTtjteR" className="social-icon nu">
            <Icon name="discord" />
            <span>discord</span>
          </a>
          <a href="https://twitter.com/squid_poker" className="social-icon nu">
            <Icon name="twitter" />
            <span>twitter</span>
          </a>
          <a href="/#" className="social-icon nu disabled">
            <Icon name="file outline" />
            <span>squid paper</span>
          </a>
        </div>
      </Segment>
      <Segment className="top-segment ">
        <p>
          <a className="sp" href="https://squid.poker">
            Squid.poker
          </a>{" "}
          will be the first provably fair No-Limit Texas hold 'em DAPP/game
          running on the Cardano blockchain. All the important parts of the
          poker game will be managed automatically via a Cardano smart contract.
          (payouts, card randomization, player verification, etc.)
        </p>
        <br />
        <p>
          To play on the{" "}
          <a className="sp" href="https://squid.poker">
            Squid.poker
          </a>{" "}
          DAPP you will need to own <span class="pink">1</span> of our avatars
          which will generate a random number when you join a game and send your
          avatar into the smart contract. Once all players join the game all
          those random numbers will be combined into a unique number seed and
          then the cards will be dealt. This will make it impossible to cheat or
          exploit the game from our end or the player’s end.
        </p>
        <br />
        <p>
          We will be periodically releasing new Avatars, custom decks, table
          skins and more every few months with a limited supply to raise money
          for the development of this DAPP! You won't need to purchase a custom
          deck to play as everyone will be provided with a default deck/table
          layout. The only thing you will need is any of our avatars we release
          on our verified policies! All of our avatars and customizations will
          be <span class="pink">100%</span> on-chain Cardano native assets.
        </p>
        <p>
          **The DAPP/Beta of the game is not due to go live for many months as
          we raise the funds to develop the game. But we have a great team that
          can make it happen with y’alls support!
        </p>
        <br />
      </Segment>
      <div className="text-center">
        <h1 className="section-header">Game Play Demo</h1>
      </div>
      <div className="poker-table">
        <img
          src={tblMin}
          alt="poker table"
          className="poker"
          onClick={handleOpen}
          role="presentation"
          aria-hidden="true"
        />
        <Modal
          open={open}
          size="large"
          className="pk"
          closeIcon
          onClose={handleClose}
        >
          <Image fluid src={tbl} alt="poker table" />
        </Modal>
      </div>
    </div>
  );
}
