import React from "react";
import { Container, Grid, Icon, Image } from "semantic-ui-react";

export default function Team() {
  return (
    <Container>
      <div className="text-center">
        <h1 className="section-header">Team</h1>
      </div>
      <Grid container stackable centered>
        {team.map((chunk, idx) => (
          <Grid.Row stretched columns={3} key={idx}>
            {chunk.map((member, i) => (
              <Grid.Column width={4} key={i}>
                <div className="team-member">
                  <Image
                    src={member.image}
                    alt={member.name}
                    title={member.name}
                  />
                  <div className="credit">
                    <h2>{member.name}</h2>
                    <p>{member.role}</p>
                    <p>
                      <Icon name="discord" /> {member.discord}
                    </p>
                  </div>
                </div>
              </Grid.Column>
            ))}
          </Grid.Row>
        ))}
      </Grid>
    </Container>
  );
}

